'use client';

import { useState, useRef, useEffect } from 'react';
import ReactMarkdown from 'react-markdown';
import { Send } from 'lucide-react';

type Message = {
  id: string;
  role: 'user' | 'system';
  content: string;
};

export default function ChatWindow() {
  const [messages, setMessages] = useState<Message[]>([
    {
      id: '1',
      role: 'system',
      content: 'Welcome to QuantPulse. I monitor NSE/BSE quant data and latest financial news. How can I assist your market research today?',
    }
  ]);
  const [input, setInput] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);
  const textareaRef = useRef<HTMLTextAreaElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isProcessing]);

  const handleInput = (e: React.ChangeEvent<HTMLTextAreaElement>) => {
    setInput(e.target.value);
    e.target.style.height = 'auto';
    e.target.style.height = `${Math.min(e.target.scrollHeight, 120)}px`;
  };

  const useSuggestion = (text: string) => {
    setInput(text);
  };

  const handleSend = async () => {
    const text = input.trim();
    if (!text) return;

    const userMsg: Message = { id: Date.now().toString(), role: 'user', content: text };
    setMessages((prev) => [...prev, userMsg]);
    setInput('');
    if (textareaRef.current) {
      textareaRef.current.style.height = 'auto';
    }

    setIsProcessing(true);

    try {
      const res = await fetch('/api/chat', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ query: text }),
      });

      if (!res.ok) throw new Error('API Error');
      const data = await res.json();
      
      if (data.system_action) {
        const store = (await import('@/store/useCanvasStore')).useCanvasStore;
        if (data.system_action.type === 'COMPARE') {
            store.getState().setIds(data.system_action.ids);
            store.getState().setView('COMPARISON');
            store.getState().openCanvas();
        }
      }
      
      setMessages((prev) => [
        ...prev,
        { id: Date.now().toString(), role: 'system', content: data.answer },
      ]);
    } catch (err) {
      setMessages((prev) => [
        ...prev,
        { id: Date.now().toString(), role: 'system', content: 'Error: Unable to reach QuantPulse core. Make sure the server is running.' },
      ]);
    } finally {
      setIsProcessing(false);
    }
  };

  return (
    <>
      <header className="chat-header w-full absolute top-0 left-0 bg-transparent z-10">
        <h2>Research Session</h2>
      </header>

      <div ref={scrollRef} className="chat-history flex-1 pt-24 pb-32">
        {messages.map((msg) => (
          <div key={msg.id} className={`message ${msg.role === 'system' ? 'system-msg' : 'user-msg'}`}>
            <div className="msg-content">
              {msg.role === 'system' ? (
                <ReactMarkdown>{msg.content}</ReactMarkdown>
              ) : (
                msg.content
              )}
              {msg.id === '1' && (
                <div className="suggestions">
                  <button className="suggestion-btn" onClick={() => useSuggestion('How is Reliance Industries performing today?')}>Reliance Industries</button>
                  <button className="suggestion-btn" onClick={() => useSuggestion('What are the latest updates on Tata Motors?')}>Tata Motors News</button>
                  <button className="suggestion-btn" onClick={() => useSuggestion('Show me the NIFTY 50 trend and recent news.')}>NIFTY 50 Analysis</button>
                </div>
              )}
            </div>
          </div>
        ))}
      </div>

      <div className="input-area absolute bottom-0 left-0 w-full z-10">
        {isProcessing && (
          <div className="processing-status" style={{ display: 'flex' }}>
            Pipeline thinking...
          </div>
        )}
        <div className="input-wrapper">
          <textarea
            ref={textareaRef}
            value={input}
            onChange={handleInput}
            onKeyDown={(e) => {
              if (e.key === 'Enter' && !e.shiftKey) {
                e.preventDefault();
                handleSend();
              }
            }}
            placeholder="Ask about stocks, indices, or market news..."
            rows={1}
          />
          <button className="send-button" onClick={handleSend} aria-label="Send Message" disabled={isProcessing}>
            <Send size={20} />
          </button>
        </div>
      </div>
    </>
  );
}
